// ─── Compute Ebbinghaus Spaced-Repetition Intervals ───
// Real intervals: 0, 1d, 3d, 7d, 14d, 30d
// Demo intervals: 0, 1min, 3min, 7min, 10min, 15min

const input = $input.first().json;
const demoMode = input.demo_mode || false;
const baseTime = new Date(input.timestamp).getTime();

const REAL_INTERVALS = [
  { label: 'Immediate',  ms: 0 },
  { label: '1 Day',      ms: 86400000 },
  { label: '3 Days',     ms: 259200000 },
  { label: '7 Days',     ms: 604800000 },
  { label: '14 Days',    ms: 1209600000 },
  { label: '30 Days',    ms: 2592000000 },
];

const DEMO_INTERVALS = [
  { label: 'Immediate',        ms: 0 },
  { label: '1 min  (1 day)',   ms: 60000 },
  { label: '3 min  (3 days)',  ms: 180000 },
  { label: '7 min  (7 days)',  ms: 420000 },
  { label: '10 min (14 days)', ms: 600000 },
  { label: '15 min (30 days)', ms: 900000 },
];

const intervals = demoMode ? DEMO_INTERVALS : REAL_INTERVALS;

const reminders = intervals.map(iv => ({
  lesson_id: input.lesson_id,
  topic_name: input.topic_name,
  user_email: input.user_email || '',
  interval_label: iv.label,
  scheduled_time: new Date(baseTime + iv.ms).toISOString(),
  sent_status: false,
  feedback: null,
}));

return reminders.map(r => ({ json: r }));

// ─── Build Notification Payload ───
const input = $input.first().json;
const now = new Date();
const scheduledTime = new Date(input.scheduled_time);
const isDue = scheduledTime <= now;

return [{
  json: {
    title: `🔔 Revise: ${input.topic_name}`,
    body: `Interval: ${input.interval_label} — Time to strengthen your memory!`,
    lesson_id: input.lesson_id,
    user_email: input.user_email,
    topic_name: input.topic_name,
    interval_label: input.interval_label,
    is_due: isDue,
    scheduled_time: input.scheduled_time,
  }
}];

