// ─── Adaptive Interval Adjustment ───
// If user remembered → multiply next interval by 1.5 (easier)
// If user forgot → multiply next interval by 0.5 (harder/sooner)

const input = $input.first().json;
const feedback = input.feedback; // 'remembered' or 'forgot'
const multiplier = feedback === 'remembered' ? 1.5 : 0.5;

return [{
  json: {
    reminder_id: input.reminder_id,
    lesson_id: input.lesson_id,
    feedback: feedback,
    adjustment_multiplier: multiplier,
    message: feedback === 'remembered'
      ? 'Great retention! Next review will be spaced further apart.'
      : 'Memory needs reinforcement. Next review moved closer.',
  }
}];
